var storyContent = {"inkVersion":21,"root":[["#","^font-size: 2em","/#","#","^color: ","/#","#","^c9a84c","/#","^SOMEWHERE NEW","\n","#","^font-size: 1em","/#","#","^color: white","/#","^A story about leaving.","\n",{"->":"act1_opening"},["done",{"#f":5,"#n":"g-0"}],null],"done",{"act1_opening":["#","^background: ","/#","#","^1a1a2e","/#","#","^color: ","/#","#","^e0e0e0","/#","#","^audio: sound/phnom_penh_city.wav","/#","#","^image: media/act%201/phnom_penh_street.jpg","/#","^Phnom Penh, Cambodia. Senior year.","\n","^One thing stands between you and the rest of your life.","\n","^The BACII, Cambodia's national standardized exam. Everyone takes it. Your score decides everything: which university, which future, which version of yourself gets to exist.","\n","^You've been studying for this longer than you want to think about.","\n",{"->":"bacii_morning"},{"#f":1}],"bacii_morning":[["^Exam day. The city feels different. Or maybe you do.","\n","^You put on your uniform, eat breakfast without tasting it. Your mom squeezes your hand at the door and doesn't say anything. That means more than anything she could've said.","\n","ev","str","^Look back at her.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Don't look back.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"bacii_morning_look"},"\n",{"#f":5}],"c-1":["^ ",{"->":"bacii_exam"},"\n",{"#f":5}]}],{"#f":1}],"bacii_morning_look":["^She's already turning away. Giving you the space to go.","\n","^You go.","\n","#","^image: media/act%201/exam_morning.jpg","/#","^You arrive to the testing center, waiting outside of the gate, waiting for it to be opened.","\n",{"->":"bacii_exam"},{"#f":1}],"bacii_exam":[["#","^color: ","/#","#","^c9a84c","/#","^— THE BACII —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^image: media/act%201/exam_room.jpg","/#","#","^audio: sound/exam.mp3","/#","^The exam room smells like chalk and nerves.","\n","^You sit down, write your name and student number at the top, take one breath.","\n","^The proctor says begin. You look down at the first question. Something in you just goes quiet.","\n","#","^color: ","/#","#","^c9a84c","/#","^You lock in.","\n","#","^color: ","/#","#","^e0e0e0","/#","ev","str","^Work through it.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"bacii_exam_working"},"\n",{"#f":5}]}],{"#f":1}],"bacii_exam_working":[["^Hours pass. You don't notice. You just work.","\n","^You walk out at 5pm into the heat and think: I did everything I could.","\n","ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^The wait is the worst part. Days just drag.","\n","ev","str","^Watch Dara pretend he's fine.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Sit next to Sokha.","/str","/ev",{"*":".^.c-1","flg":20},"ev","str","^Check on Menghour.","/str","/ev",{"*":".^.c-2","flg":20},{"c-0":["^ ",{"->":"wait_dara"},"\n",{"#f":5}],"c-1":["^ ",{"->":"wait_sokha"},"\n",{"#f":5}],"c-2":["^ ",{"->":"wait_menghour"},"\n",{"#f":5}]}],{"#f":1}],"wait_dara":["^Dara keeps saying \"we're fine, we're definitely fine\" in a way that means he's not sure at all. You don't call him on it. Neither does anyone else.","\n",{"->":"bacii_waiting_end"},{"#f":1}],"wait_sokha":["^Sokha's already decided she passed and is planning her celebration. You just let her talk. Her being so sure about it kind of helps.","\n",{"->":"bacii_waiting_end"},{"#f":1}],"wait_menghour":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^Menghour is quiet, which is how you know he's scared. You sit next to him and don't say anything. That's enough.","\n",{"->":"bacii_waiting_end"},{"#f":1}],"bacii_waiting_end":["^You are all scared.","\n",{"->":"bacii_results_day"},{"#f":1}],"bacii_results_day":[["#","^color: ","/#","#","^c9a84c","/#","^— RESULTS DAY —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^audio: sound/LEASE.mp3","/#","#","^image: media/act%201/results_crowd.jpg","/#","^Results are announced publicly. They read every name, room number, and grade out loud, in front of everyone.","\n","^You've been standing here with your friends for twenty minutes and it feels like forever. The announcer's going through it alphabetically.","\n","^Your palms are sweating. The voice crackles through the speaker.","\n","ev","str","^Keep listening.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"name_waiting"},"\n",{"#f":5}]}],{"#f":1}],"name_waiting":[["^Names. Grades. Names. Grades. The list keeps going.","\n","^You look straight ahead. You don't look at your friends. You just listen.","\n","ev","str","^Listen for your name.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"name_called"},"\n",{"#f":5}]}],{"#f":1}],"name_called":[["^And then.","\n","#","^color: ","/#","#","^c9a84c","/#","^\"","ev",{"VAR?":"playerName"},"out","/ev","^. Room 203. Grade B.\"","\n","#","^color: ","/#","#","^e0e0e0","/#","^A pause that lasts less than a second but feels much longer.","\n","#","^color: ","/#","#","^c9a84c","/#","^\"You passed. Congratulations.\"","\n","#","^color: ","/#","#","^e0e0e0","/#","ev","str","^Let it land.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"bacii_passed"},"\n",{"#f":5}]}],{"#f":1}],"bacii_passed":[["ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"#","^STOPAUDIO","/#","#","^audio: sound/congratss.mp3,,0.15","/#","^You passed.","\n","^It takes a second to land. Then Sokha screams, Dara grabs you, and Menghour, quiet, steady Menghour, lifts you clean off the ground. All three of them, lifting you. You're laughing and crying at the same time and honestly you can't tell which is which and it doesn't matter.","\n","^You passed.","\n","#","^color: ","/#","#","^c9a84c","/#","^You actually passed.","\n","#","^color: ","/#","#","^e0e0e0","/#","ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^You cry. Like, really cry, the ugly kind that's been building for months. Sokha cries too, immediately, like she was just waiting for permission. Dara pretends he isn't. He definitely is.","\n","^Menghour keeps his arm around you. \"I told you,\" he says. \"I always told you.\"","\n","^You don't remember him ever saying that. Doesn't matter. You'll let him have it.","\n","ev","str","^Celebrate the moment.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"bacii_aftermath"},"\n",{"#f":5}]}],{"#f":1}],"bacii_aftermath":[["#","^audio: sound/khmer_restaurant.m4a","/#","#","^image: media/act%201/family_dinner.jpg","/#","^That night your parents take you to your favorite restaurant. Your dad orders way too much food. Your mom keeps reaching over to squeeze your hand.","\n","^At some point your dad goes quiet and says: \"Now the real work begins.\"","\n","^He means it nicely. You know that. But it lands weird. Because you're already thinking about the Rutgers letter on your desk at home, the visa appointment you still haven't scheduled, all the stuff that comes next.","\n","ev","str","^Think about what comes next.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Stay in this moment a little longer.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"transition_to_embassy"},"\n",{"#f":5}],"c-1":["^ ",{"->":"stay_in_moment"},"\n",{"#f":5}]}],{"#f":1}],"stay_in_moment":["ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^You push it away. Tomorrow's problem.","\n","^Tonight there's good food, your parents across the table, your phone going crazy with messages from Sokha and Dara and Menghour and basically everyone from school.","\n","^Tonight you just passed.","\n",{"->":"transition_to_embassy"},{"#f":1}],"transition_to_embassy":["#","^audioloop: sound/LEASE.mp3","/#","#","^color: ","/#","#","^c9a84c","/#","^— WEEKS LATER —","\n","#","^color: ","/#","#","^e0e0e0","/#","^The BACII's done. Now there's one thing left before any of this gets real.","\n","^The American Embassy. The visa interview. The thing that either lets you go or doesn't.","\n",{"->":"embassy_intro"},{"#f":1}],"rooftop_scene":[["#","^audio: sound/phnom_penh_city.wav,,0.15","/#","#","^image: media/act%201/rooftop_sunset.jpg","/#","^Thursday late afternoon. The heat's doing what it always does, just sitting on everything.","\n","^You're on the rooftop of Sokha's building, the one on Street 63 with the broken elevator everyone uses anyway.","\n","^Four of you up here. Sokha, Dara, Menghour, and you.","\n","^Same rooftop. Same people. But something's different today and everyone knows it.","\n","ev","str","^Look out at the city.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Look at your friends.","/str","/ev",{"*":".^.c-1","flg":20},"ev","str","^Think about how many times you've been up here.","/str","/ev",{"*":".^.c-2","flg":20},{"c-0":["^ ",{"->":"city_view"},"\n",{"#f":5}],"c-1":["^ ",{"->":"friends_view"},"\n",{"#f":5}],"c-2":["^ ",{"->":"rooftop_memory"},"\n",{"#f":5}]}],{"#f":1}],"rooftop_memory":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^You've been coming up here since you were fourteen. After exams, after bad days, after good ones. The elevator's been broken the whole time. Nobody's ever fixed it. Nobody's ever complained.","\n","^You wonder if you'll think about this rooftop when you're in New Jersey. You already know you will.","\n",{"->":"rooftop_conversation"},{"#f":1}],"city_view":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^You lean on the railing and look out.","\n","^Phnom Penh goes in every direction. Tuk-tuks weaving below, the smell of grilled corn from the street vendor on the corner, the Mekong catching the sun somewhere in the distance.","\n","^You've looked at this city your whole life and never actually looked at it.","\n","ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},{"->":"rooftop_conversation"},{"#f":1}],"friends_view":["ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^Sokha's talking too fast about something, the way she does when she's trying not to feel something. Dara's on his phone but not really. Menghour's just sitting there with his arms on his knees, staring at nothing.","\n","^They know. You haven't brought it up again today but they know.","\n",{"->":"rooftop_conversation"},{"#f":1}],"rooftop_conversation":[["^\"So,\" Sokha says finally. \"When do you leave?\"","\n","^\"Three weeks,\" you say.","\n","^Dara puts his phone down. Menghour looks over.","\n","^\"Three weeks,\" Dara repeats. \"That's nothing.\"","\n","^\"That's nothing,\" you agree.","\n","ev","str","^\"I'm scared.\"","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^\"I'm ready. I think.\"","/str","/ev",{"*":".^.c-1","flg":20},"ev","str","^\"I don't really want to talk about it.\"","/str","/ev",{"*":".^.c-2","flg":20},"ev","str","^\"Are you guys going to be okay?\"","/str","/ev",{"*":".^.c-3","flg":20},"ev","str","^Say nothing. Just look at the city.","/str","/ev",{"*":".^.c-4","flg":20},{"c-0":["^ ",{"->":"response_scared"},"\n",{"#f":5}],"c-1":["^ ",{"->":"response_ready"},"\n",{"#f":5}],"c-2":["^ ",{"->":"avoidant_response"},"\n",{"#f":5}],"c-3":["^ ",{"->":"response_about_them"},"\n",{"#f":5}],"c-4":["^ ",{"->":"silent_response"},"\n",{"#f":5}]}],{"#f":1}],"response_scared":[["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^\"I'm scared,\" you say. It comes out easier than you expected.","\n","^Sokha nods immediately. \"Obviously.\"","\n","^\"That's normal,\" Menghour says. \"That means it matters.\"","\n","^Dara leans back. \"You survived the BACII. You can survive New Jersey.\"","\n","^You laugh despite yourself. \"Those are very different things.\"","\n","^\"Are they though?\"","\n","ev","str","^\"What am I even going to do without you guys?\"","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Just sit with it.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"missing_friends"},"\n",{"#f":5}],"c-1":["^ ",{"->":"sit_with_it"},"\n",{"#f":5}]}],{"#f":1}],"response_ready":[["^\"I'm ready,\" you say. \"I think.\"","\n","^Sokha raises an eyebrow. \"You think?\"","\n","^\"I mean, I've been preparing for this for two years. The applications, the BACII, the visa. At some point you just have to go.\"","\n","^\"Very inspirational,\" Dara says flatly. \"You should put that on a poster.\"","\n","^\"Shut up.\"","\n","ev","str","^\"But I'm also terrified.\"","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^\"I just don't want to waste it.\"","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"response_scared"},"\n",{"#f":5}],"c-1":["^ ",{"->":"dont_waste_it"},"\n",{"#f":5}]}],{"#f":1}],"dont_waste_it":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^\"I just don't want to waste it,\" you say. \"Like, people don't get this. My parents didn't get this. I can't go all the way to America and come back with nothing.\"","\n","^Menghour says: \"You won't.\"","\n","^He doesn't explain how he knows. He just says it like it's already true.","\n",{"->":"rooftop_continue"},{"#f":1}],"response_about_them":[["ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^\"Are you guys going to be okay?\" you ask.","\n","^\"Did you just ask if WE'RE going to be okay,\" Dara says.","\n","^\"You're the one leaving.\"","\n","^\"I know. Are you?\"","\n","^Sokha laughs softly. \"We'll figure it out. We always do.\" She pauses. \"Will you?\"","\n","ev","str","^\"Yes.\"","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^\"I don't know.\"","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"optimistic_response"},"\n",{"#f":5}],"c-1":["^ ",{"->":"avoidant_response"},"\n",{"#f":5}]}],{"#f":1}],"missing_friends":["ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^\"What am I even going to do without you guys?\"","\n","^Nobody has a good answer. Dara makes a joke about time zones that doesn't land. Sokha squeezes your arm.","\n","^\"You'll call,\" Menghour says finally. \"And we'll pick up.\"","\n","^Simple as that. You hope it's that simple.","\n",{"->":"rooftop_continue"},{"#f":1}],"sit_with_it":["^Nobody pushes you to say more. That's the thing about people who've known you long enough.","\n","^The sun is lower now. The city is getting louder the way it always does at dusk.","\n",{"->":"rooftop_continue"},{"#f":1}],"optimistic_response":["^\"It's going to be fine,\" you say. You're not sure if you're telling them or yourself.","\n","^Sokha nods slowly. \"Of course it is.\" She sounds like she means it.","\n","^Dara just says, \"You better text us.\"","\n","^\"Every day,\" you say.","\n","^You won't. Not every day. You don't know that yet.","\n",{"->":"rooftop_continue"},{"#f":1}],"avoidant_response":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^\"Yeah,\" Menghour says. \"Okay.\"","\n","^Nobody pushes it. That's the thing about people who've known you long enough. They know when not to push.","\n",{"->":"rooftop_continue"},{"#f":1}],"silent_response":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^You don't say anything. You just look out at the city.","\n","^Sokha reaches over and bumps your shoulder with hers. She doesn't say anything either.","\n","^That's enough.","\n",{"->":"rooftop_continue"},{"#f":1}],"rooftop_continue":[["#","^image: media/act%201/rooftop_night.jpg","/#","^The four of you stay up there until the sun's gon.","\n","^Someone orders food at some point. You eat on the rooftop while the city lights come on below, and for a while nobody brings up New Jersey or Rutgers or three weeks or any of it.","\n","^Just the four of you. Phnom Penh at night.","\n","ev","str","^Take a photo of everyone.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Just remember it.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"rooftop_photo"},"\n",{"#f":5}],"c-1":["^ ",{"->":"rooftop_remember"},"\n",{"#f":5}]}],{"#f":1}],"rooftop_photo":["ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^You take out your phone. \"Can we take a photo?\"","\n","^Dara groans. Sokha immediately fixes her hair. Menghour just shifts over to make room.","\n","^You take three. In the best one, Dara is mid-eye-roll and Sokha is laughing at him and Menghour is looking at the camera and you can see the city behind all of you, lit up and sprawling.","\n","^You set it as your lock screen that night.","\n","^You still have it.","\n",{"->":"airport_goodbye"},{"#f":1}],"rooftop_remember":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^You don't take a photo. You just look.","\n","^You try to memorize it: the way Sokha laughs, the way Dara talks with his hands, the way Menghour goes quiet when something means something to him.","\n","^You think: I don't need a photo. I'll remember this.","\n","^You will. But it will cost you something every time.","\n","#","^STOPAUDIOLOOP","/#",{"->":"airport_goodbye"},{"#f":1}],"airport_goodbye":[["#","^audioloop: sound/ballade.mp3,,0.30","/#","#","^background: ","/#","#","^1a1a2e","/#","#","^color: ","/#","#","^c9a84c","/#","^— THE DAY —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^audio: sound/airport_ambience.m4a","/#","#","^image: media/act%201/airport_departure.webp","/#","^Phnom Penh International Airport. Early morning.","\n","^Two suitcases. One carry-on. A folder of documents you've checked forty times.","\n","^Your parents are there. Sokha, Dara and Menghour are there.","\n","^Everyone is trying very hard to be normal about it.","\n","ev","str","^Say goodbye.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"goodbye_scene"},"\n",{"#f":5}]}],{"#f":1}],"goodbye_scene":["^Right before you go through security, you turn around. Your mom is holding it together, your dad has his hand on her shoulder, and Sokha is already crying and pretending she isn't. You think: I should memorize this. You think: I won't need to, I'll see them again soon. Both of those things are true. Neither of them helps.","\n","^Before you go through, your mom grabs your hand and presses something into your palm. A platinum ring, thin and simple, no ceremony about it. \"From me,\" she says. That's all. You put it on. It fits. You wave. You go through.","\n","#","^color: ","/#","#","^c9a84c","/#","^— END OF ACT 1 —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^STOPAUDIOLOOP","/#",{"->":"act2_flight"},{"#f":1}],"act2_flight":[["#","^background: ","/#","#","^0a0a1a","/#","#","^audio: sound/airplane_ takeoff.wav","/#","#","^image: media/act%202/plane_window.jpg","/#","#","^color: ","/#","#","^c9a84c","/#","^— ACT 2: THE IN-BETWEEN —","\n","#","^color: ","/#","#","^e0e0e0","/#","^Nineteen hours.","\n","^You watch Phnom Penh disappear under the clouds. Then it's just grey, then blue, then more blue for a really long time.","\n","ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^You don't really sleep. You just drift in and out of something. In the dark you keep thinking about your bed back home, the weight of the blanket, the sound of the street at night. The tuk-tuks. The neighbors. The dogs.","\n","^The BACII. The embassy. The rooftop. The airport. All of it behind you now.","\n","^You wonder if you're ready. You decide it doesn't matter.","\n","#","^audio: sound/airplane_cabin.wav","/#","ev","str","^Land in America","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"flight_land"},"\n",{"#f":5}]}],{"#f":1}],"flight_land":[["#","^audio: sound/new_york.mp3","/#","#","^color: ","/#","#","^c9a84c","/#","^John F. Kennedy International Airport. New York City.","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^image: media/act%202/jfk_winter.jpg","/#","^January.","\n","^The plane touches down. The cabin fills with seatbelts clicking, people moving, phones buzzing back to life.","\n","^You look out at the tarmac. Grey sky. Bare trees.","\n","^It hits you. Not dramatically, not like in a movie. Just quietly, all at once.","\n","#","^color: ","/#","#","^c9a84c","/#","^You're here.","\n","#","^color: ","/#","#","^e0e0e0","/#","ev","str","^Go through arrivals.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"arrivals_hall"},"\n",{"#f":5}]}],{"#f":1}],"arrivals_hall":[["^The arrivals hall is enormous and loud and everyone seems to know exactly where they're going.","\n","^You follow the signs for immigration. You join a line. You wait.","\n","^\"Purpose of visit?\"","\n","^\"Student. Rutgers University.\"","\n","^He stamps it without looking up. You walk through.","\n","ev","str","^Find the exit.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"jfk_exit"},"\n",{"#f":5}]}],{"#f":1}],"jfk_exit":[["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"#","^audio: sound/jfk_winter.wav","/#","^You step outside and the cold just hits. Not like Phnom Penh cool, not like plane AC. This is a different thing entirely. It has weight. It finds the back of your neck immediately.","\n","^You stop. People move around you.","\n","#","^color: ","/#","#","^c9a84c","/#","^This is what January feels like here.","\n","#","^color: ","/#","#","^e0e0e0","/#","ev","str","^Look for your aunt.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"find_aunt"},"\n",{"#f":5}]}],{"#f":1}],"find_aunt":[["^And then, there she is.","\n","^Your aunt, holding a small handwritten sign with your name on it, grinning like she's been waiting for this for months.","\n","^She hugs you before you can get your suitcase handle properly and says into your shoulder: \"You made it. You actually made it.\"","\n","ev","str","^\"I made it.\"","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Just hug her back and don't say anything.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"aunt_reunion_a"},"\n",{"#f":5}],"c-1":["^ ",{"->":"aunt_reunion_b"},"\n",{"#f":5}]}],{"#f":1}],"aunt_reunion_a":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^\"I made it,\" you say.","\n","^Saying it out loud is something. Nineteen hours, the BACII, the embassy, the rooftop, the airport. All of that in three words.","\n","^Your aunt looks at your face. \"You look exhausted.\"","\n","^\"I am exhausted.\"","\n","^\"Good. Means it was real.\" She picks up one of your bags. \"Come on. Bus is this way.\"","\n","#","^STOPAUDIO","/#",{"->":"bus_to_nj"},{"#f":1}],"aunt_reunion_b":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^You don't say anything. You just hold on for a second.","\n","^She smells like home. The same soap, the same shampoo your mom uses. Something in your chest just does something.","\n","^You let go before it gets worse.","\n","^\"Bus is this way,\" she says, like she already knew.","\n",{"->":"bus_to_nj"},{"#f":1}],"bus_to_nj":["#","^background: ","/#","#","^0d1117","/#","#","^color: ","/#","#","^e0e0e0","/#","#","^audio: sound/night_bus.wav","/#","#","^audioloop: sound/comptine.mp3","/#","#","^image: media/act%202/night_highway.jpg","/#","^Three hours to New Jersey. Past midnight. Your aunt falls asleep. You don't.","\n","ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^Dara sent: \"????? you there yet\". Menghour: \"Let us know when you land.\"","\n","^You type: \"landed. on the bus. it's cold.\"","\n","^Sokha replies in thirty seconds with seventeen emojis.","\n","^You smile. Then you put your phone away because looking at it too long is gonna make things worse.","\n","^You touch the ring on your finger. Still there.","\n",{"->":"bus_arrival"},{"#f":1}],"bus_arrival":["#","^image: media/act%202/nj_street_night.png","/#","^3am. The bus stops.","\n","^\"Welcome to New Jersey,\" your aunt says.","\n","ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^Quiet street. Bare trees. Nobody around.","\n","^Back home, 3am still has noise. Here it's just silent.","\n","^You've never heard this much silence in your life.","\n",{"->":"aunts_house"},{"#f":1}],"aunts_house":[["#","^background: ","/#","#","^0f1923","/#","#","^color: ","/#","#","^c9a84c","/#","^— THE FIRST WEEK —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^image: media/act%202/house_interior.webp","/#","^Your aunt and uncle's house is warm and small and smells like someone else's life.","\n","^\"Sleep,\" she says. \"Everything else tomorrow.\"","\n","^You're asleep before you finish the thought.","\n","ev","str","^The next morning.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"first_morning"},"\n",{"#f":5}]}],{"#f":1}],"first_morning":[["#","^audioloop: sound/nature_day.mp3","/#","^For half a second you have no idea where you are. Then it all comes back.","\n","^You stare at the ceiling. New Jersey. Okay. First day.","\n","ev","str","^Get up.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"first_morning_up"},"\n",{"#f":5}]}],{"#f":1}],"first_morning_up":[["^Your aunt makes breakfast. Eggs, toast, orange juice. Your uncle is already up, already dressed, already heading out. He puts a hand on your shoulder on his way past and doesn't say anything. That's enough.","\n","^You eat it and try not to think about rice porridge, or the bánh mì cart on your street, or the way your mom makes fried rice with the crispy bits at the bottom.","\n","^The eggs are fine. Everything's fine.","\n","ev","str","^Look out the window at New Jersey in the daytime.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Call your parents to say you're okay.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"first_week_window"},"\n",{"#f":5}],"c-1":["^ ",{"->":"first_week_parents"},"\n",{"#f":5}]}],{"#f":1}],"first_week_window":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^Daylight doesn't make it feel less foreign. Just more visible.","\n","^Neat houses. Dead lawns. A street with no one on it. A sky the colour of concrete.","\n","^Phnom Penh would be loud by now. Street vendors, school kids on motos, the whole city in motion.","\n","^Here it's just quiet.","\n",{"->":"first_week_montage"},{"#f":1}],"first_week_parents":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"ev",{"VAR?":"friendsRemembered"},1,"+","/ev",{"VAR=":"friendsRemembered","re":true},"^You call home. Your mom picks up immediately.","\n","^\"How is it? Are you cold? Are you eating?\"","\n","^\"It's cold. I'm eating. I'm okay.\"","\n","^\"You don't sound okay.\"","\n","^\"I'm just tired, Mom.\"","\n","^Pause. \"Your dad wants to say something.\"","\n","^He gets on: \"Study hard.\" That's it. But the way he says it, like it cost him something, you get what he means.","\n","^\"I will,\" you say.","\n",{"->":"first_week_montage"},{"#f":1}],"first_week_montage":[["#","^color: ","/#","#","^c9a84c","/#","^— THINGS YOU LEARN IN THE FIRST WEEK —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^audio: sound/campus_ambience.mp3","/#","#","^image: media/act%202/karen_sandwich.jpg","/#","^The portions are enormous. You order a sandwich and eat half of it and feel guilty about the rest.","\n","^The bus runs on a schedule. No one honks. You miss the chaos of home more than you expected.","\n","^People hold doors open for strangers. You're always a half-second too slow to say thank you.","\n","ev","str","^The hardest part.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"accent_scene"},"\n",{"#f":5}]}],{"#f":1}],"accent_scene":[["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^The hardest part is the English.","\n","^You knew English, studied it for years, wrote your whole Rutgers application in it. You thought you were fine.","\n","^But classroom English and real English aren't the same thing.","\n","^People talk fast. They drop parts of words, use phrases you've never heard. And when you speak, you can see it sometimes, just for a second, that little pause while they figure out your accent.","\n","^You're not hard to understand. But the gap between what you mean and what lands is bigger than you expected.","\n","ev","str","^Try to talk to someone anyway.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Go quiet for a while.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"accent_try"},"\n",{"#f":5}],"c-1":["^ ",{"->":"accent_quiet"},"\n",{"#f":5}]}],{"#f":1}],"accent_try":["^You try anyway. A cashier at the campus store. A girl at the bus stop.","\n","^It's messy and you repeat yourself sometimes. But it works. Mostly.","\n","^The girl at the bus stop is from the Philippines. She's been here a semester. She says it gets easier, and says it like she knows.","\n","^You believe her.","\n",{"->":"act2_end"},{"#f":1}],"accent_quiet":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^For a while you just go quiet.","\n","^Not rude, just careful. You listen more than you talk. You figure out the rhythm of conversations before you jump in. You text instead of call when you can.","\n","^It's not failure. It's just what it costs to be somewhere new.","\n",{"->":"act2_end"},{"#f":1}],"act2_end":["#","^color: ","/#","#","^c9a84c","/#","^— END OF ACT 2 —","\n","#","^color: ","/#","#","^e0e0e0","/#","^Classes start in three days.","\n","^You've been here a week. You know how to use the bus, how to order food, how to dress for weather that feels like it has a personal problem with you.","\n","^You video call Sokha. She asks what it's like. You can't explain it without worrying her, so you just say: \"Big. It's really big.\"","\n","^She laughs. \"You'll get used to it.\"","\n","^You're working on it.","\n",{"->":"act3_opening"},{"#f":1}],"act3_opening":["#","^background: ","/#","#","^0f0f1a","/#","#","^color: ","/#","#","^c9a84c","/#","^— ACT 3: RUTGERS —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^audio: sound/campus_ambience.mp3","/#","#","^image: media/act%203/rutgers_campus.jpg","/#","^Spring semester, 2023. Camden, New Jersey.","\n","^Five classes. A student ID with a bad photo. A campus map so creased it's starting to tear.","\n","^You were here. You were doing this.","\n","^You were also, if you're being honest, completely lost.","\n",{"->":"meet_chris"},{"#f":1}],"meet_chris":["^The morning after you landed, before classes even start, your uncle calls someone over.","\n","^His name is Chris. He's a sophomore. He shows up at the door looking relaxed in a way you are not yet capable of feeling, and your uncle introduces you like you're a package he's been waiting to hand off.","\n","^\"Show him around,\" your uncle says.","\n","^Chris looks at you. You look at Chris.","\n","^\"Alright,\" he says. \"Let's go.\"","\n",{"->":"chris_tour"},{"#f":1}],"chris_tour":[["^Chris takes you around campus in a way no orientation packet could. Not the official version, the real one. Where the good bathrooms are. Where the dining hall is. How to read the bus schedule without wanting to cry.","\n","^He talks a lot. You listen a lot. Your English is functional but fast conversation is still a wall, and Chris speaks fast.","\n","^But he slows down when he notices you've gone quiet. That matters.","\n","ev","str","^Ask him something you've been wondering.","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^Just take it all in.","/str","/ev",{"*":".^.c-1","flg":20},{"c-0":["^ ",{"->":"chris_question"},"\n",{"#f":5}],"c-1":["^ ",{"->":"chris_listen"},"\n",{"#f":5}]}],{"#f":1}],"chris_question":["^\"Is it always this cold?\" you ask.","\n","^Chris laughs. Actually laughs. \"Bro, this is nothing. Wait until February.\"","\n","^You file that away under things to worry about later.","\n",{"->":"chris_711"},{"#f":1}],"chris_listen":["^You don't say much. You just walk and look and try to map the campus onto the map in your head, which keeps failing. It's not a big campus, nothing like New Brunswick, but it's bigger than anything you had back home, and that's enough to feel lost in.","\n","^Chris doesn't seem to mind the quiet. That's the first thing you actually like about him.","\n",{"->":"chris_711"},{"#f":1}],"chris_711":[["#","^audio: sound/convenience_store.mp3","/#","#","^image: media/act%203/7eleven.webp","/#","^At some point you pass a 7-Eleven and you stop.","\n","^You're hungry, you thought to yourself \"lets take a peek and see what all the hype is about\"","\n","^You look around. You look at Chris.","\n","^\"Do they have rice?\"","\n","^Chris stares at you for a second. Then he makes a face like he's trying very hard not to laugh and failing completely.","\n","^\"Bro, you're actually such a FOB LOL\" he says. \"No rice. This is 7-Eleven.\"","\n","#","^color: ","/#","#","^c9a84c","/#","^You end up with a hotdog.","\n","#","^color: ","/#","#","^e0e0e0","/#","^It is not rice. It is fine. You eat it standing on the sidewalk in the January cold while Chris explains the concept of a Slurpee, and somehow, for the first time since you landed, you feel something that might be okay.","\n","ev","str","^First day of classes.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"first_day"},"\n",{"#f":5}]}],{"#f":1}],"first_day":[["#","^color: ","/#","#","^c9a84c","/#","^— FIRST DAY —","\n","#","^color: ","/#","#","^e0e0e0","/#","^Five classes. That's what you signed up for.","\n","^Programming Fundamentals. Calculus 1. Introduction to World Religions. Introduction to Philosophy. Introduction to Film and Video.","\n","^You wrote them all down in your phone the night before. You read them back to yourself like a list of promises.","\n","ev","str","^Go to your first class.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"first_class_overwhelm"},"\n",{"#f":5}]}],{"#f":1}],"first_class_overwhelm":[["^The first week of classes is like being handed a book in a language you almost speak.","\n","^You understand maybe seventy percent. The sentences move fast, the professors don't pause, the other students seem to already know things you don't.","\n","^Film and Video feels okay. Images don't need translation. That class feels like breathing.","\n","^But Calculus.","\n","ev","str","^Calculus.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"calc_first_week"},"\n",{"#f":5}]}],{"#f":1}],"calc_first_week":[["#","^background: ","/#","#","^0d0d1a","/#","#","^color: ","/#","#","^e0e0e0","/#","#","^image: media/act%203/calc_notebook.jpeg","/#","^Calculus is different.","\n","^Math doesn't care about your accent. Numbers are numbers. You know this.","\n","^But the language around the math is a wall.","\n","^Your professor is Sara. She writes fast and talks faster. The words she uses, derivative, limit, continuity, you have never heard these in English before. Not in a classroom.","\n","^You open your notebook and start writing down everything you don't understand.","\n","#","^color: ","/#","#","^c9a84c","/#","^Every word. Every phrase. Every thing she says that you can't follow.","\n","#","^color: ","/#","#","^e0e0e0","/#","^You go home and open Google and start at the top of the list.","\n","ev","str","^Keep going.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"calc_the_work"},"\n",{"#f":5}]}],{"#f":1}],"calc_the_work":[["^Class. Notebook full of words. Home. Google. Try to connect the English to the math. Fail. Try again. not enough sleep . Repeat.","\n","^You fall behind. Catch up a little. Fall behind again.","\n","^One afternoon you stay after class. Sara is erasing the board.","\n","^\"Professor,\" you say. \"There's a language barrier. For me. I understand the math but the words...\" You pause. \"I'm still learning.\"","\n","^She turns around and looks at you.","\n","^\"Come to office hours. We'll figure it out.\"","\n","ev","str","^Go to office hours.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"office_hours"},"\n",{"#f":5}]}],{"#f":1}],"office_hours":[["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^You go every day.","\n","^Most students show up once before an exam. You are there Tuesday, Thursday, sometimes Friday.","\n","^When you don't have the English for what you're asking, you show her the notebook. She fills in the gaps.","\n","^Slowly, the wall gets lower. The words start to mean things.","\n","ev","str","^The moment it clicks.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"calc_clicks"},"\n",{"#f":5}]}],{"#f":1}],"calc_clicks":[["#","^audio: sound/pencil_writing.mp3,1.5","/#","#","^image: media/act%203/dorm_night.jpg","/#","^It happens in the middle of a problem set, alone in your room at 11pm.","\n","^You're working through a derivative and you don't have to stop. You don't have to look anything up. Your hand just moves and the answer comes out and it's right.","\n","^You sit there for a second.","\n","#","^color: ","/#","#","^c9a84c","/#","^Oh.","\n","#","^color: ","/#","#","^e0e0e0","/#","^You go back and do the next one. Also right. And the next. Right.","\n","^You think about your high school teachers in Phnom Penh who wrote you off. You think about the BACII results being read out loud in front of everyone. You think about writing down words you didn't know in a notebook at 8am in New Jersey.","\n","^You keep going.","\n","ev","str","^The rest of the semester.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"semester_montage"},"\n",{"#f":5}]}],{"#f":1}],"semester_montage":[["#","^color: ","/#","#","^c9a84c","/#","^— THE REST OF THE SEMESTER —","\n","#","^color: ","/#","#","^e0e0e0","/#","^Chris becomes a constant. He drives you places when the bus doesn't go there. He introduces you to people. He eats at the dining hall with you and complains about the food the same way you do, which makes it better somehow.","\n","^You make friends in Philosophy and Film and World Religions, people you eat lunch with, people whose names you actually learn. By April it stops feeling like you have to translate yourself before you can speak.","\n","^April is also Khmer New Year. Your mom video calls and turns the phone so you can see the whole apartment: the decorations, the food on the table, your aunt laughing at something off screen. Sokha leans into frame and holds up a bowl of something like a trophy.","\n","^You're sitting in your dorm room with a vending machine sandwich. You laugh. It hurts at the same time.","\n","^The language barrier doesn't disappear. It just shrinks to a manageable size.","\n","^But good things have a ceiling on them now. You'll do something right and right underneath it is the weight of everything it cost to be here. What you left. What your mom is carrying so you can sit in this classroom and take these notes. You can't fully land inside the good moments yet. Maybe that's just how it goes for a while.","\n","ev","str","^End of semester.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"end_of_semester"},"\n",{"#f":5}]}],{"#f":1}],"end_of_semester":[["#","^audio: sound/pencil_writing.mp3,1.5","/#","#","^image: media/act%203/library_night.jpeg","/#","^Finals. The library at midnight. Coffee you don't really like but drink anyway because everyone else is drinking it.","\n","^Calculus final. You sit down. You look at the first problem.","\n","^You write your name at the top of the page.","\n","#","^color: ","/#","#","^c9a84c","/#","^You lock in.","\n","#","^color: ","/#","#","^e0e0e0","/#","ev","str","^Results.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"semester_results"},"\n",{"#f":5}]}],{"#f":1}],"semester_results":[["^GPA: 3.6.","\n","^You read it three times.","\n","^3.6. First semester. Five classes. A language you were still learning. A country you'd been in for four months.","\n","^You text Chris: \"3.6\"","\n","^He replies in thirty seconds: \"LETS GO BRO\"","\n","^You call home. Your mom picks up immediately. You tell her. She makes the sound again. The one from the embassy phone call. The one you still don't have a word for. Your dad gets on the phone.","\n","^He says: \"I knew you would.\"","\n","^He has never said this before. It lands somewhere deep and stays there.","\n","ev","str","^One more thing.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"sara_switch"},"\n",{"#f":5}]}],{"#f":1}],"sara_switch":[["#","^audio: sound/campus_ambience.mp3","/#","^At the end of the semester Sara calls you into office hours.","\n","^\"You should switch to a Bachelor of Science,\" she says. \"Not Arts, Science. The way you think through problems, a B.S. opens more doors.\"","\n","^You think about all of the moments that she has helped you, the notebook, the wall. Later that evening, you emailed your advisor saying that you want to switch from a BA to a BS.","\n","^You went back to tell professor Sara but she sits there and just nods likes she already understood what has happened before you even tell her.","\n","^The next semester you take Calc 2 with her but unfortunately, she leaves for maternity leave","\n","ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^You're still waiting for her to come back everyday  You have so many things you want to tell her. Not even big things, just small moments that somehow felt important because you thought you’d tell her later. Now they just sit with you, unfinished, like sentences that never made it out of your mouth.","\n","^Some people change the direction of your life and don't even realize it.","\n","ev","str","^One more thing.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"dads_passing"},"\n",{"#f":5}]}],{"#f":1}],"dads_passing":[["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"#","^color: ","/#","#","^c9a84c","/#","^— A YEAR HAS PASSED —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^image: media/act%203/hallway_phone.jpg","/#","#","^audio: sound/phone_buzz.mp3","/#","^The summer after first year. You're in class when it happens.","\n","^Your phone lights up. Your sister's name. Once. Then again. Then a third time. ","#","^audio: sound/phone_buzz.mp3","/#","\n","ev","str","^Step outside and pick up.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"dads_call"},"\n",{"#f":5}]}],{"#f":1}],"dads_call":[["^You slip out the back of the classroom.","\n","^You call her back.","\n","^The line connects and you can tell immediately something is wrong. She's barely speaking above a whisper. Your mom is there too, you can hear her in the background. Both of them trying to hold their voices together, trying to keep it quiet, like if they say it too softly it won't be as real.","\n","^You stand in the hallway and listen to them cry for almost a minute before either of them can say the words.","\n","^Then they say the words.","\n","ev","str","^...","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"dads_aftermath"},"\n",{"#f":5}]}],{"#f":1}],"dads_aftermath":[["#","^audioloop: sound/Best%20Friend.mp3","/#","^Your dad is gone. He passed...","\n","^You can't go home. The ticket costs more than you have and your visa situation is complicated. You sit with that for a long time before you accept it.","\n","^You go back to class the next day.","\n","^Nobody knows. You don't tell anyone. You sit in the back and take notes and come home every night and call your mom and listen to her breathe on the phone until she falls asleep.","\n","^You become the man of the family without a ceremony, without a conversation. It just happens. One day you're someone's son and the next day you're the person your mom calls when something breaks.","\n","^The ring on your finger is heavier now. You hadn't realized how much of it was about him until he was gone.","\n","^Life keeps moving,it doesn't stop, EVER.","\n","ev","str","^The night walk.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"night_walk_intro"},"\n",{"#f":5}]}],{"#f":1}],"night_walk_intro":[["#","^background: ","/#","#","^070714","/#","#","^color: ","/#","#","^c9a84c","/#","^— ACT 4: THE NIGHT —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^image: media/act%204/night_campus.jpg","/#","^Junior year now. Two years since that first semester.","\n","^You're still here. Still going.","\n","^Campus is quiet in the way it only gets when most people have already gone home. Paths empty. Buildings lit from inside but nobody in them.","\n","^You're walking. Not going anywhere. Just walking.","\n","ev","str","^Keep walking.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"night_walk_1"},"\n",{"#f":5}]}],{"#f":1}],"night_walk_1":[["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^The cold doesn't bother you anymore.","\n","^Two years ago it stopped you at the door of your aunt and uncle's house. Now you just pull your jacket tighter and keep going.","\n","^You walk past the building where Calc 1 was. Past the dining hall. Past the bus stop where you once stood for twenty minutes because you didn't know which bus to take and were too embarrassed to ask.","\n","^This campus is yours now. It didn't used to feel that way.","\n","ev","str","^Keep walking.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"night_walk_2"},"\n",{"#f":5}]}],{"#f":1}],"night_walk_2":[["^And then, without deciding to, you stop.","\n","^You're in the middle of a path between two buildings. Nobody around. The kind of quiet that has weight to it.","\n","^And it hits you.","\n","^Not loudly. Not like a wave. Just arriving, the way the cold arrived at JFK. Quietly, through a gap.","\n","ev","str","^What is it?","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"night_walk_realisation"},"\n",{"#f":5}]}],{"#f":1}],"night_walk_realisation":[["ev",{"VAR?":"homesickness"},4,">=","/ev",[{"->":".^.b","c":true},{"b":["\n","^It's Sokha. It's Dara. It's Menghour.","\n","^It's the rooftop on Street 63 and the broken elevator and the food they ordered when nobody wanted to say goodbye. It's the sound of Phnom Penh at night, the tuk-tuks and the music and the city that never fully turns off.","\n","^It's your mom's hand squeezing yours at the door on exam morning. Your dad, gone a year now, who said \"I knew you would\" on the phone like a man paying a debt he'd been carrying for years. You still think he's watching. You have to believe that.","\n","^It's everything you walked away from at Phnom Penh International Airport with two suitcases and a carry-on, and all the ways you didn't understand what you were leaving until you were already gone.","\n","^You stand there on a path in New Jersey and you let it be what it is.","\n","^Heavy. Real. Worth it.","\n",{"->":".^.^.^.7"},null]}],[{"->":".^.b"},{"b":["\n","ev",{"VAR?":"friendsRemembered"},3,">=","/ev",[{"->":".^.b","c":true},{"b":["\n","^It's smaller than you expected. Not a flood, more like a tide coming in slowly and then stopping.","\n","^You think about the rooftop. About Sokha crying and pretending not to. About Menghour lifting you off the ground on results day. About Chris in the 7-Eleven saying bro, no rice.","\n","^You think about how many people have held you up without you asking.","\n","^You stand there and let that be enough.","\n",{"->":".^.^.^.8"},null]}],[{"->":".^.b"},{"b":["\n","^It's quiet. That's all.","\n","^You've been moving so fast: the BACII, the visa, the flight, the bus, the classes, the office hours, the finals. And for the first time in months there's nothing to move toward. Just the path and the lit buildings and the cold.","\n","^You don't feel sad exactly. You feel the distance. Between here and home. Between who you were on that rooftop and who you are now.","\n","^It's not bad. It's just true.","\n",{"->":".^.^.^.8"},null]}],"nop","\n",{"->":".^.^.^.7"},null]}],"nop","\n","ev","str","^Keep walking.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"night_walk_end"},"\n",{"#f":5}]}],{"#f":1}],"night_walk_end":[["^You don’t call anyone. You don’t text anyone. You just stand there for a while, letting the quiet sit with you, and then you start walking again.","\n","^Somewhere between first year and now, things shifted. Dara stopped texting first, Menghour’s replies got shorter, and Sokha still sends voice notes sometimes, but they’re about her life now, her job, her new people. It’s not anyone’s fault. It’s just what happens when everyone moves forward at the same time, even if no one really says it out loud.","\n","#","^image: media/act%204/ring.jpg","/#","^You spin the ring on your finger, your mom’s ring, your dad’s weight in it.","\n","^Two years in, everything looks different. Your GPA is a 4.0, you have more aid, and English comes out without you thinking about it. The version of you who stood at that bus stop too scared to ask for directions wouldn’t recognize who you are now.","\n","ev","str","^Keep walking.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"night_walk_end_2"},"\n",{"#f":5}]}],{"#f":1}],"night_walk_end_2":[["^And still, even with all of that, you catch yourself reaching for your dad like it’s instinct, like he’s still just a call away if you press the right button at the right time, and then it hits you again, the same way it always does, that he’s not. It’s been a year, but your mind still forgets for a second in the moments it matters, and you’re left holding that silence like something physical. You tell yourself he’s watching, because you have to, because some days that’s the only version of it that doesn’t completely undo you.","\n","^The city is still there, and you are still here. Both are true at the same time, and that’s the part no one really explains about leaving. It never becomes one or the other. It just becomes something you carry instead of something that carries you.","\n","#","^color: ","/#","#","^c9a84c","/#","^So you keep walking.","\n","#","^color: ","/#","#","^e0e0e0","/#","ev","str","^.....","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"pre_ending"},"\n",{"#f":5}]}],{"#f":1}],"pre_ending":[{"->":"ending"},{"#f":1}],"ending":["#","^background: ","/#","#","^070714","/#","#","^color: ","/#","#","^c9a84c","/#","^— SOMEWHERE NEW —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^image: media/act%204/night_sky.jpg","/#","^You stop walking for a second and look up.","\n","^\"Not bad, ey?\" you say, to nobody, to the sky, maybe to him. \"I guess I left behind all of those things back home.\"","\n","^Do you want to go back? Yes. Of course. You miss everyone, every day, in ways you don't always have words for.","\n","^But you can't. Not yet. You've got somewhere to be.","\n","#","^color: ","/#","#","^c9a84c","/#","^Masters in Business Analytics. Here I come.","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^color: ","/#","#","^888888","/#","^GPA: 4.0. Aid: increased. English: fluent.","\n","^Dad: gone. Still watching.","\n","^Home: still there. Still yours.","\n","^You: still here. Still going. still pushing through.","\n","#","^color: ","/#","#","^c9a84c","/#","^— FIN —","\n","end",{"#f":1}],"embassy_intro":[["#","^background: ","/#","#","^0d0d0d","/#","#","^color: ","/#","#","^ffffff","/#","#","^audio: sound/airport_ambience.m4a","/#","#","^image: media/branching/embassy_waiting.webp","/#","^The American Embassy in Phnom Penh is on Street 96.","\n","^You've walked past it before but you've never been inside. The line starts outside at 7am. You get there at 6:45. There are already twelve people ahead of you.","\n","^Your appointment is at 9:15. You have a folder with every document they asked for: acceptance letter, financial records, passport photos, the DS-160 form you filled out three times because you kept making mistakes.","\n","^You sit down and wait.","\n","^You open the folder. Acceptance letter: check. Bank statements: check. Passport: check. The I-20 form from Rutgers: check. You've checked it so many times the edges of the papers are soft. Everything is there. Everything has always been there. You know that. But you check again anyway.","\n","^Around you, the waiting room hums with quiet anxiety. A man in a collared shirt rehearses something under his breath. A teenage boy your age bounces his leg. A woman nearby holds a toddler on her lap and stares straight ahead.","\n","^Everyone in this line wants something. Everyone in this line is a little scared.","\n","^You try not to think about what happens if they say no. You think about it anyway.","\n","ev","str","^Wait for your name.","/str","/ev",{"*":".^.c-0","flg":20},{"c-0":["^ ",{"->":"interview_waiting_room"},"\n",{"#f":5}]}],{"#f":1}],"interview_waiting_room":["#","^image: media/branching/consular_window.jpeg","/#","^At 9:22 they call your name.","\n","^You walk to the window. The consular officer is a woman in her forties. She looks at your passport, then at you.","\n","^\"Good morning,\" she says in English.","\n","^\"Good morning,\" you say back. Your voice comes out steady. Good.","\n","^She opens your file.","\n",{"->":"interview_q1"},{"#f":1}],"interview_q1":[["#","^color: ","/#","#","^c9a84c","/#","^\"What school will you be attending?\"","\n","#","^color: ","/#","#","^e0e0e0","/#","ev","str","^\"Rutgers University. In Camden, New Jersey.\"","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^\"University of Pennsylvania.\"","/str","/ev",{"*":".^.c-1","flg":20},"ev","str","^\"Temple University.\"","/str","/ev",{"*":".^.c-2","flg":20},{"c-0":["^ ",{"->":"interview_q1_correct"},"\n",{"#f":5}],"c-1":["^ ",{"->":"interview_q1_wrong"},"\n",{"#f":5}],"c-2":["^ ",{"->":"interview_q1_wrong"},"\n",{"#f":5}]}],{"#f":1}],"interview_q1_correct":["^She makes a note.","\n",{"->":"interview_q3"},{"#f":1}],"interview_q1_wrong":["^She looks up from the file. Looks at you. Then back at the file.","\n","^A pause.","\n","^\"The school on your I-20 is Rutgers University.\" She sets the folder down. \"That's not what you said.\"","\n","^Your face goes hot. You start to speak. She raises one hand slightly, not unkind, just final.","\n","^\"I'm going to have to deny this application. You're welcome to reapply.\"","\n","^She slides your folder back under the window.","\n",{"->":"visa_denied"},{"#f":1}],"interview_q3":[["#","^color: ","/#","#","^c9a84c","/#","^\"Do you intend to return to Cambodia after completing your studies?\"","\n","#","^color: ","/#","#","^e0e0e0","/#","^This is the one you were warned about. Everyone gets asked this. Everyone knows what they're looking for.","\n","ev","str","^\"Yes. My family is here. I plan to come back.\"","/str","/ev",{"*":".^.c-0","flg":20},"ev","str","^\"I'm not sure yet. I want to see where my education takes me.\"","/str","/ev",{"*":".^.c-1","flg":20},"ev","str","^\"No. I intend to stay in the United States.\"","/str","/ev",{"*":".^.c-2","flg":20},"ev","str","^Pause before answering.","/str","/ev",{"*":".^.c-3","flg":20},{"c-0":["^ ",{"->":"interview_q3_yes"},"\n",{"#f":5}],"c-1":["^ ",{"->":"interview_q3_honest"},"\n",{"#f":5}],"c-2":["^ ",{"->":"interview_q3_no"},"\n",{"#f":5}],"c-3":["^ ",{"->":"interview_q3_pause"},"\n",{"#f":5}]}],{"#f":1}],"interview_q3_yes":["^\"My family is here,\" you say. \"I plan to come back.\"","\n","^She writes something down. You can't see what.","\n",{"->":"interview_end"},{"#f":1}],"interview_q3_honest":["ev",{"VAR?":"homesickness"},1,"+","/ev",{"VAR=":"homesickness","re":true},"^It comes out before you can stop it. \"I'm not sure yet. I want to see where my education takes me.\"","\n","^A beat. She looks at you.","\n","^Then she nods once and writes something down.","\n","^You realize you're holding your breath.","\n",{"->":"interview_end"},{"#f":1}],"interview_q3_no":["^The words leave your mouth and you know immediately.","\n","^She doesn't react visibly. She just writes something down, closes the folder, and folds her hands.","\n","^\"A student visa requires the intent to return to your home country upon completion of your studies.\" Her voice is even. \"I can't approve this application.\"","\n","^She slides your folder back.","\n",{"->":"visa_denied"},{"#f":1}],"interview_q3_pause":["^You pause.","\n","^You think about your friends. About Sokha's shoulder against yours on that rooftop. The city at dusk.","\n","^\"Yes,\" you say. \"I plan to come back.\"","\n",{"->":"interview_end"},{"#f":1}],"visa_denied":["#","^background: ","/#","#","^0d0d0d","/#","#","^color: ","/#","#","^ff4444","/#","^— VISA DENIED —","\n","#","^color: ","/#","#","^e0e0e0","/#","#","^audio: sound/phnom_penh_city.wav","/#","^You walk back out through the waiting room.","\n","^The man in the collared shirt is still rehearsing his answers under his breath. The woman with the toddler looks up at you. You don't make eye contact.","\n","^You push through the heavy door and step out into the Phnom Penh heat and you stand there on Street 96 and you don't move for a long time.","\n","^Your phone is in your pocket. Your mom is waiting for a call.","\n","^You don't know how to make it.","\n","#","^color: ","/#","#","^888888","/#","^The future you planned is still out there somewhere.","\n","^But not today.","\n","^Not like this.","\n","#","^color: ","/#","#","^ff4444","/#","^— END —","\n","#","^color: ","/#","#","^888888","/#","^[ You can restart and try again. ]","\n","end",{"#f":1}],"interview_end":["^She closes the folder.","\n","^\"Your visa has been approved. You'll receive your passport within five business days.\"","\n","ev",true,"/ev",{"VAR=":"hasVisa","re":true},"^You say thank you. You walk back through the waiting room. You push through the heavy door and step back out into the Phnom Penh heat and you stand there on Street 96 for a moment and don't move.","\n","#","^color: ","/#","#","^c9a84c","/#","^It's real now.","\n","#","^color: ","/#","#","^e0e0e0","/#","^You call your mom. She picks up on the second ring.","\n","^You say: \"It's approved.\"","\n","^She makes a sound you don't have a word for. Something between relief and something else.","\n","^\"Come home,\" she says. \"I'll make dinner.\"","\n",{"->":"transition_to_rooftop"},{"#f":1}],"transition_to_rooftop":["#","^color: ","/#","#","^c9a84c","/#","^— WEEKS LATER —","\n","#","^color: ","/#","#","^e0e0e0","/#","^The visa is in your passport. The flight is booked. The packing has started, then stopped, then started again. Rutgers sent a welcome packet with a campus map and a list of things to bring.","\n","^There are three weeks left.","\n",{"->":"rooftop_scene"},{"#f":1}],"global decl":["ev","str","^V","/str",{"VAR=":"playerName"},false,{"VAR=":"hasVisa"},0,{"VAR=":"friendsRemembered"},0,{"VAR=":"homesickness"},"/ev","end",null],"#f":1}],"listDefs":{}};